arena.java21_code:
// 初始化 (2 次 JNI)
long world = RigidBodyNative.worldCreate(0, -9.81, 0);
ByteBuffer buf = RigidBodyNative.worldGetArenaDirectByteBuffer(world);

// 每帧循环 (零 JNI 读写)
while (running) {
    int bodyCount = buf.getInt(32);
    for (int i = 0; i < bodyCount; i++) {
        double px = buf.getDouble(128 + i*96 + 8);
    }
    // 写入力 — 零 JNI
    int cmdOff = buf.getInt(52);
    buf.putDouble(cmdOff + 8, 100.0);

    // 触发物理 — 仅 1 次 JNI
    RigidBodyNative.worldStep(world, 1.0 / 60.0);
    RigidBodyNative.worldResetSharedArenaEvents(world);
}

java.mc_code:
dependencies {
    implementation 'org.polaris2023:mps-rigid-body:0.1.4'
}

public class PhysicsMod {
    private long world;
    public void init() {
        world = RigidBodyNative.worldCreate(0, -9.81, 0);
        RigidBodyNative.worldRegisterCelestialGravity(world, 3, 8);
        ByteBuffer arena = RigidBodyNative.worldGetArenaDirectByteBuffer(world);
    }
    public void onServerTick() {
        RigidBodyNative.worldStep(world, 1.0 / 20.0);
    }
    public void shutdown() {
        RigidBodyNative.worldDestroy(world);
    }
}
